public static str getError()
{
    SysInfologEnumerator    sysInfologEnumerator;
    SysInfologMessageStruct infoMessageStruct;
    str                     logMessage;
    str                           logString;
    str                          ret;
    int                          i;
    #Define.NewLine('\n')
    sysInfologEnumerator = SysInfologEnumerator::newData(infolog.infologData());
    while (sysInfologEnumerator.moveNext())
    {
        i = 1;
        if (logMessage)
        {
            logMessage += #Newline;
        }
        infoMessageStruct = SysInfologMessageStruct::construct(sysInfologEnumerator.currentMessage());

        while (i <= infoMessageStruct.prefixDepth())
        {
            logString = logString + infoMessageStruct.preFixTextElement(i) + '. ';
            i++;
        }

        logString = logString + infoMessageStruct.message();
        logMessage = logMessage + infoMessageStruct.message();
    }

    infolog().clear();

    return logMessage;
}

public void createHeader()
{
    PurchPurchaseAgreementHeaderV2Entity    purchAgreementHeader;

    VendTable                               vendTable;
    DirPartyBaseEntity                      vendTableDirParty;
    DictEnum                                dictEnumCommitmentType = new DictEnum(enumNum(CommitmentType));

    vendTable                                                   = VendTable::find(vendAccountLoc);
    if(purchNumberSequenceLoc != "")
    {
        purchAgreementHeader.PurchaseAgreementId                    = purchNumberSequenceLoc;
    }
    else
    {
        purchAgreementHeader.PurchaseAgreementId       = NumberSeq::newGetNum(PurchParameters::numRefPurchAgreementId(),false).num();
    }
    purchAgreementHeader.PurchaseAgreementClassificationName    = agreementClassificationLoc;
    purchAgreementHeader.AGREEMENTSTATUS                        = AgreementState::OnHold;
    purchAgreementHeader.AgreementType                          = AgreementType;
    purchAgreementHeader.AgreementVendorAccountNumber           = vendTable.AccountNum;

    if(wfStatus == "Approved")
    {
        purchAgreementHeader.AgreementWorkflowStatus                = PurchAgreementWorkflowStatus::Approved;
    }
    else 
    {
        if(wfStatus == "Submitted")
        {
            purchAgreementHeader.AgreementWorkflowStatus                = PurchAgreementWorkflowStatus::Submitted;
        }
        else 
        {
            purchAgreementHeader.AgreementWorkflowStatus                = PurchAgreementWorkflowStatus::Draft;
        }
    }
   // purchAgreementHeader.AgreementWorkflowStatus                = PurchAgreementWorkflowStatus::Submitted;
    purchAgreementHeader.BuyerAccountNum                        = BuyerAccount;
    purchAgreementHeader.BuyerBank                              = BuyerBank;
    purchAgreementHeader.BuyingLegalEntityId                    = curExt();
    purchAgreementHeader.CurrencyCode                            = currencyCodeNew;
    purchAgreementHeader.PaymentTermsName                        = PaymentTerms;
    purchAgreementHeader.PaymentScheduleName = PaymentSchedule;
    purchAgreementHeader.CashDiscountCode = CashDiscountCode;
    purchAgreementHeader.MiscChargeGroup = MiscChargeGroup;
    purchAgreementHeader.DeliveryModeCode = DeliveryMode;
    purchAgreementHeader.DeliveryTermsCode = DeliveryTerm;
    purchAgreementHeader.ContactPersonId = Contact;
    purchAgreementHeader.MethodOfPayment = MethodOfPayment;
    purchAgreementHeader.VendorReference = VendorReference;
   //purchAgreementHeader.DefaultCommitmentType                  = dictEnumCommitmentType.symbol2Value(conpeek(con, 11)); //check
    purchAgreementHeader.DefaultEffectiveDate                   = EffectiveDateLoc;//today();
    purchAgreementHeader.DefaultExpirationDate                  = Expiration;
    //purchAgreementHeader.DeliveryModeCode                       = ModeOfDelivery;
    //purchAgreementHeader.DeliveryTermsCode                      = TermsOfDelDescription;
    purchAgreementHeader.DocumentTitle                          = DocumentTitle;
    purchAgreementHeader.ETG_Vendor                             = ETGVendor;
        purchAgreementHeader.ExternalDocumentReference              = ExternalDocumentReference;

    if(NotifyToDifferentParty == "Yes")
    {
        purchAgreementHeader.Notifytodifferentparty                 = NoYes::Yes;
    }
    else
    {
        purchAgreementHeader.Notifytodifferentparty                 = NoYes::No;
    }
    purchAgreementHeader.PortOfDischarge                        = PortOfDischarge;
    select firstonly Description from placeOfDischarge where placeOfDischarge.PlaceOfDischarge == PortOfDischarge;
    purchAgreementHeader.PortOfDischargeDesc                    = placeOfDischarge.Description;
    purchAgreementHeader.PortOfLoading                          = PortOFLoading;
    select firstonly Description from placeOfLoading where placeOfLoading.PlaceOfLoading == PortOFLoading;
    purchAgreementHeader.PortOfLoadingDesc                      = placeOfLoading.Description;
    purchAgreementHeader.PurchaseOrderPoolId                    = PurchasePool;
    purchAgreementHeader.SellerAccountNum                   = SellerAccount;
    purchAgreementHeader.SellerBank                             = SellerBank;
    purchAgreementHeader.Through                                = Broker;

    if(Broker && CommissionValue)
    {
        if(CommissionType == "Quantity")
        {
            purchAgreementHeader.BrokerageCommissionType     = ETGBrokerageCommissionType::Quantity;
        }
        else
        {
            purchAgreementHeader.BrokerageCommissionType     = ETGBrokerageCommissionType::Percent;
        }
        purchAgreementHeader.BrokerageCommissionValue = str2Num(CommissionValue);
    }

    purchAgreementHeader.TermPaymDescription   = TermsOfPaymentDescription;

    if(futures == "Yes")
    {
